// Calcola la data odierna in formato YYYY-MM-DD
const today = $now.toFormat('yyyy-MM-dd');

const allRows = $input.all();

// Filtra righe il cui timestamp_arrivo appartiene a oggi
const todayRows = allRows.filter(item => {
  const ts = item.json.timestamp_arrivo;
  if (!ts) return false;
  return String(ts).startsWith(today);
});

const totale_richieste = todayRows.length;
const ai_handled = todayRows.filter(r => r.json.tipo === 'ai_handled').length;
const escalated = todayRows.filter(r => r.json.tipo === 'escalated').length;

const escalatedRisolti = todayRows.filter(r =>
  r.json.tipo === 'escalated' &&
  r.json.stato === 'risolto' &&
  r.json.timestamp_risolto
);

let tempo_medio_risposta_h = 0;
if (escalatedRisolti.length > 0) {
  const totalMs = escalatedRisolti.reduce((sum, r) => {
    const arrivo = new Date(r.json.timestamp_arrivo).getTime();
    const risolto = new Date(r.json.timestamp_risolto).getTime();
    return sum + (risolto - arrivo);
  }, 0);
  const avgMs = totalMs / escalatedRisolti.length;
  tempo_medio_risposta_h = Math.round((avgMs / (1000 * 60 * 60)) * 100) / 100;
}

return [{
  json: { data: today, totale_richieste, ai_handled, escalated, tempo_medio_risposta_h }
}];
